	private void PowerStateChanged(ValueChangedEventArgs e)
	{
		ParticleAcceleratorPowerState obj;
		switch (e.Value)
		{
		default:
			return;
		case 0:
			obj = ParticleAcceleratorPowerState.Standby;
			break;
		case 1:
			obj = ParticleAcceleratorPowerState.Level0;
			break;
		case 2:
			obj = ParticleAcceleratorPowerState.Level1;
			break;
		case 3:
			obj = ParticleAcceleratorPowerState.Level2;
			break;
		case 4:
			obj = ParticleAcceleratorPowerState.Level3;
			break;
		}
		StateSpinBox.SetButtonDisabled(true);
		this.OnPowerState?.Invoke(obj);
	}

